// Fisher-Yates shuffle algorithm to randomize verse order.
static void shuffle(Verse *array, int size) {
    for (int i = size - 1; i > 0; i--) {
        int j = rand() % (i + 1);
        Verse temp = array[j];
        array[j] = array[i];
        array[i] = temp;
    }
}

